# Search for occurrences with "اخت" and "نكح"/"زوج"
def search_hadiths_by_keywords(keywords, limit=50):
    res=[]
    for rec, txt in hadith_texts:
        nt = normalize_ar(txt)
        ok=True
        for kw in keywords:
            if kw not in nt:
                ok=False
                break
        if ok:
            res.append((rec, txt))
            if len(res)>=limit:
                break
    return res

